              <h3 className="text-xs font-semibold text-slate-500 uppercase mb-3">Compliance Overview</h3>
              <div className="space-y-3">
                <div>
                  <div className="flex justify-between text-xs mb-1">
                    <span className="text-slate-400">PPE Compliance</span>
                    <span className="text-emerald-500">{safetyScore.ppe}%</span>
                  </div>
                  <div className="h-1.5 bg-slate-800 rounded-full overflow-hidden">
                    <div className="h-full bg-emerald-500 rounded-full" style={{ width: `${safetyScore.ppe}%` }}></div>
                  </div>
                </div>
                <div>
                  <div className="flex justify-between text-xs mb-1">
                    <span className="text-slate-400">Behavioral Safety</span>
                    <span className="text-blue-500">{safetyScore.behavior}%</span>
                  </div>
                  <div className="h-1.5 bg-slate-800 rounded-full overflow-hidden">
                    <div className="h-full bg-blue-500 rounded-full" style={{ width: `${safetyScore.behavior}%` }}></div>
                  </div>
                </div>
              </div>
            </div>
          </aside>
        </main>

        {/* AI Report Modal */}
        {isReportOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
            <div className="bg-slate-900 border border-slate-700 w-full max-w-2xl rounded-xl shadow-2xl flex flex-col max-h-[85vh]">
              <div className="flex items-center justify-between p-4 border-b border-slate-800">
                <h3 className="text-lg font-bold text-white flex items-center gap-2">
                  <FileText className="w-5 h-5 text-blue-500" />
                  AI Shift Incident Report
                </h3>
                <button 
                  onClick={() => setIsReportOpen(false)}
                  className="text-slate-400 hover:text-white transition-colors"
                >
                  <X className="w-5 h-5" />
                </button>
              </div>

              <div className="flex-1 p-6 overflow-y-auto custom-scrollbar bg-slate-950/50 font-mono text-sm leading-relaxed">
                {isGeneratingReport ? (
                  <div className="flex flex-col items-center justify-center h-48 space-y-4">
                    <Loader2 className="w-8 h-8 text-blue-500 animate-spin" />
                    <p className="text-slate-400 animate-pulse text-center">Synthesizing Safety Data via Gemini Intelligence Engine...</p>
                  </div>
                ) : (
                  <div className="prose prose-invert max-w-none whitespace-pre-wrap">
                    {reportContent}
                  </div>
                )}
              </div>

              <div className="p-4 border-t border-slate-800 flex justify-end gap-3 bg-slate-900 rounded-b-xl">
                <button
                  onClick={() => setIsReportOpen(false)}
                  className="px-4 py-2 text-sm text-slate-300 hover:text-white hover:bg-slate-800 rounded-lg transition-colors"
                >
                  Close
                </button>
                <button
                  onClick={() => {
                    navigator.clipboard.writeText(reportContent);
                  }}
                  disabled={isGeneratingReport || !reportContent}
                  className="px-4 py-2 text-sm bg-blue-600 hover:bg-blue-500 text-white rounded-lg disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                >
                  Copy to Clipboard
                </button>
              </div>
            </div>
          </div>
        )}

        <div className="hidden">
          {visibleCameras.map(cam => (
            <React.Fragment key={`proc-${cam.id}`}>
              <video
                ref={el => { if (el) videoRefs.current.set(cam.id, el); }}
                muted
                playsInline
                autoPlay
                width={CAMERA_WIDTH}
                height={CAMERA_HEIGHT}
              />
              <canvas
                ref={el => { if (el) canvasRefs.current.set(cam.id, el); }}
                width={CAMERA_WIDTH}
                height={CAMERA_HEIGHT}
              />
            </React.Fragment>
          ))}
        </div>
      </div>
    </AuthGuard>
  );
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Lock, Fingerprint, ShieldCheck, AlertCircle } from 'lucide-react';

interface AuthGuardProps {
  children: React.ReactNode;
}

const INACTIVITY_TIMEOUT = 300000; // 5 minutes in ms
const MOCK_PIN = "1234"; // In production, verify against hashed storage

export const AuthGuard: React.FC<AuthGuardProps> = ({ children }) => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [pin, setPin] = useState("");
  const [error, setError] = useState(false);
  const [isBiometricScanning, setIsBiometricScanning] = useState(false);
  const [lockedReason, setLockedReason] = useState<'initial' | 'timeout'>('initial');

  // Inactivity Timer Ref
  // Fix: Added initial value undefined to useRef to satisfy TypeScript requirements (Expected 1 argument)
  const inactivityTimerRef = useRef<number | undefined>(undefined);

  const lock = useCallback((reason: 'initial' | 'timeout' = 'timeout') => {
    setIsAuthenticated(false);
    setLockedReason(reason);
  }, []);

  const resetInactivityTimer = useCallback(() => {
    if (inactivityTimerRef.current !== undefined) {
      window.clearTimeout(inactivityTimerRef.current);
    }
    if (isAuthenticated) {
      inactivityTimerRef.current = window.setTimeout(() => lock('timeout'), INACTIVITY_TIMEOUT);
    }
  }, [isAuthenticated, lock]);

  // Handle PIN Entry
  const handlePinSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (pin === MOCK_PIN) {
      unlock();
    } else {
      setError(true);
      setPin("");
      setTimeout(() => setError(false), 2000);
    }
  };

  const unlock = useCallback(() => {
    setIsAuthenticated(true);
    setPin("");
    setError(false);
    resetInactivityTimer();
  }, [resetInactivityTimer]);

  // Biometric Simulation
  const handleBiometricScan = () => {
    setIsBiometricScanning(true);
    setTimeout(() => {
      setIsBiometricScanning(false);
      unlock();
    }, 1500);
  };

  useEffect(() => {
    // Monitor user activity
    const events = ['mousedown', 'keydown', 'scroll', 'touchstart'];
    const handleActivity = () => resetInactivityTimer();

    if (isAuthenticated) {
      events.forEach(event => window.addEventListener(event, handleActivity));
      resetInactivityTimer();
    }

    return () => {
      events.forEach(event => window.removeEventListener(event, handleActivity));
      if (inactivityTimerRef.current !== undefined) {
        window.clearTimeout(inactivityTimerRef.current);
      }
    };
  }, [isAuthenticated, resetInactivityTimer]);

  if (isAuthenticated) {
    return <>{children}</>;
  }

  return (
    <div className="fixed inset-0 z-50 bg-slate-950 flex flex-col items-center justify-center p-4">
      <div className="w-full max-w-md bg-slate-900 border border-slate-800 rounded-2xl shadow-2xl p-8 text-center relative overflow-hidden">
        {/* Decorative Grid Background */}
        <div className="absolute inset-0 opacity-10" style={{
          backgroundImage: 'radial-gradient(#3b82f6 1px, transparent 1px)',
          backgroundSize: '20px 20px'
        }}></div>

        <div className="relative z-10">
          <div className="mx-auto bg-slate-800 w-20 h-20 rounded-full flex items-center justify-center mb-6 shadow-inner border border-slate-700">
            {lockedReason === 'timeout' ? (
              <Lock className="w-10 h-10 text-amber-500" />
            ) : (
              <ShieldCheck className="w-10 h-10 text-blue-500" />
            )}
          </div>

          <h2 className="text-2xl font-bold text-white mb-2">HSE Guardian Enterprise</h2>
          <p className="text-slate-400 text-sm mb-8">
            {lockedReason === 'timeout' 
              ? "Session timed out due to inactivity. Please re-authenticate." 
              : "Secure Terminal Access. Authorization Required."}
          </p>

          <form onSubmit={handlePinSubmit} className="space-y-4">
            <div>
              <input
                type="password"
                maxLength={4}
                value={pin}
                onChange={(e) => setPin(e.target.value)}
                placeholder="ENTER SECURITY PIN"
                className={`w-full bg-slate-950 border-2 ${error ? 'border-rose-500 animate-shake' : 'border-slate-700 focus:border-blue-500'} rounded-lg px-4 py-3 text-center text-2xl tracking-[0.5em] font-mono text-white placeholder-slate-700 focus:outline-none transition-all`}
                autoFocus
              />
              {error && (
                <p className="text-rose-500 text-xs mt-2 flex items-center justify-center gap-1">
                  <AlertCircle className="w-3 h-3" /> INVALID CREDENTIALS
                </p>
              )}
            </div>

            <button
              type="submit"
              className="w-full bg-blue-600 hover:bg-blue-500 text-white font-bold py-3 rounded-lg transition-colors shadow-lg shadow-blue-900/20"
            >
              UNLOCK TERMINAL
            </button>
          </form>

          <div className="mt-8 pt-6 border-t border-slate-800">
            <button
              onClick={handleBiometricScan}
              disabled={isBiometricScanning}
              className={`group flex items-center justify-center gap-2 w-full text-slate-400 hover:text-white transition-colors ${isBiometricScanning ? 'cursor-wait' : ''}`}
            >
              <div className={`p-2 rounded-full ${isBiometricScanning ? 'bg-emerald-500/20 text-emerald-400' : 'bg-slate-800 group-hover:bg-slate-700'}`}>
                <Fingerprint className={`w-6 h-6 ${isBiometricScanning ? 'animate-pulse' : ''}`} />
              </div>
              <span className="text-sm font-medium">
                {isBiometricScanning ? 'SCANNING BIOMETRICS...' : 'USE BIOMETRIC AUTH'}
              </span>
            </button>
          </div>
        </div>
      </div>

      <div className="mt-8 text-xs text-slate-600 font-mono">
        SYSTEM ID: HSE-AI-8842 • SECURE CONNECTION: TLS 1.3
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { ChevronLeft, Info, Maximize, Settings, ShieldAlert, Activity, Crosshair, Target } from 'lucide-react';
import { CameraDevice } from '../types';
import { VideoPlayer } from './VideoPlayer';

interface SingleCameraViewProps {
  camera: CameraDevice;
  onBack: () => void;
}

export const SingleCameraView: React.FC<SingleCameraViewProps> = ({ camera, onBack }) => {
  const [isFocusing, setIsFocusing] = useState(false);
  const [focusComplete, setFocusComplete] = useState(false);

  const performAutoFocus = useCallback(async () => {
    if (!camera.stream || camera.status !== 'online') return;

    setIsFocusing(true);
    setFocusComplete(false);

    // Hardware focus attempt (if supported by the browser and device)
    const videoTrack = camera.stream.getVideoTracks()[0];
    if (videoTrack && typeof videoTrack.applyConstraints === 'function') {
      try {
        const capabilities = videoTrack.getCapabilities() as any;
        if (capabilities.focusMode && capabilities.focusMode.includes('continuous')) {
          await videoTrack.applyConstraints({
            advanced: [{ focusMode: 'continuous' }] as any
          });
        }
      } catch (err) {
        console.warn('Hardware focus adjustment not supported or failed:', err);
      }
    }

    // Visual focus simulation sequence
    setTimeout(() => {
      setIsFocusing(false);
      setFocusComplete(true);
      // Clear the "Focus Complete" flash after 2 seconds
      setTimeout(() => setFocusComplete(false), 2000);
    }, 1800);
  }, [camera.stream, camera.status]);

  useEffect(() => {
    if (camera.status === 'online') {
      performAutoFocus();
    }
  }, [camera.status, performAutoFocus]);

  return (
    <div className="flex flex-col h-full bg-black relative group overflow-hidden animate-in fade-in zoom-in-95 duration-300">
      {/* Top Header Overlay */}
      <div className="absolute top-0 left-0 right-0 z-20 p-4 bg-gradient-to-b from-black/80 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-4">
            <button 
              onClick={onBack}
              className="p-2 bg-slate-800/80 hover:bg-slate-700 rounded-full text-white transition-colors border border-slate-700/50"
            >
              <ChevronLeft className="w-5 h-5" />
            </button>
            <div>
              <h2 className="text-xl font-bold text-white leading-tight flex items-center gap-2">
                {camera.name}
                <span className="text-xs font-mono bg-blue-500/20 text-blue-400 px-2 py-0.5 rounded border border-blue-500/30 uppercase">Live</span>
              </h2>
              <p className="text-sm text-slate-300 uppercase tracking-widest opacity-80">{camera.location}</p>
            </div>
          </div>

          <div className="flex items-center gap-3">
            <div className="flex flex-col items-end mr-4">
              <span className="text-[10px] text-slate-400 uppercase font-bold tracking-tighter">Stream Health</span>
              <div className="flex gap-1">
                {[1,2,3,4,5].map(i => (
                  <div key={i} className={`w-1 h-3 rounded-full ${i <= 4 ? 'bg-emerald-500' : 'bg-slate-700'}`} />
                ))}
              </div>
            </div>
            <button 
              onClick={performAutoFocus}
              className={`p-2 bg-slate-800/80 hover:bg-slate-700 rounded-lg text-white border border-slate-700/50 transition-all ${isFocusing ? 'animate-pulse text-blue-400' : ''}`}
              title="Manual Re-focus"
            >
              <Target className="w-5 h-5" />
            </button>
            <button className="p-2 bg-slate-800/80 hover:bg-slate-700 rounded-lg text-white border border-slate-700/50"><Settings className="w-5 h-5" /></button>
          </div>
        </div>
      </div>

      {/* Main Video Area */}
      <div className="flex-1 relative flex items-center justify-center">
        {camera.active && camera.stream ? (
          <VideoPlayer 
            stream={camera.stream} 
            className={`w-full h-full object-contain transition-all duration-700 ${isFocusing ? 'blur-[2px] scale-[1.01]' : 'blur-0 scale-100'}`} 
          />
        ) : (
          <div className="flex flex-col items-center justify-center text-slate-700">
            <ShieldAlert className="w-20 h-20 mb-4 opacity-20" />
            <p className="text-xl font-mono uppercase tracking-widest animate-pulse">Establishing Secure Uplink...</p>
          </div>
        )}

        {/* AI Focus Overlay UI */}
        {isFocusing && (
          <div className="absolute inset-0 z-10 flex items-center justify-center pointer-events-none">
            <div className="relative">
              <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-48 h-48 border-2 border-blue-500/30 rounded-lg animate-ping"></div>
              <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-32 h-32 border border-blue-400/50 rounded-lg animate-[pulse_1s_infinite]"></div>
              <div className="flex flex-col items-center gap-2">
                <Crosshair className="w-12 h-12 text-blue-400 animate-spin-slow opacity-80" />
                <span className="text-[10px] font-mono text-blue-400 uppercase tracking-[0.3em] font-bold bg-black/40 px-2 py-1 backdrop-blur-sm rounded">
                  AI Auto-Focusing...
                </span>
              </div>
            </div>
          </div>
        )}

        {/* Focus Complete Indicator */}
        {focusComplete && (
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 z-10 pointer-events-none animate-out fade-out duration-1000">
            <div className="bg-emerald-500/20 border border-emerald-500/50 backdrop-blur-md px-4 py-2 rounded-full flex items-center gap-2 shadow-[0_0_20px_rgba(16,185,129,0.3)]">
              <Target className="w-4 h-4 text-emerald-400" />
              <span className="text-xs font-mono text-emerald-400 uppercase font-bold tracking-widest">Focus Calibrated</span>
            </div>
          </div>
        )}

        {/* Telemetry Overlays */}
        <div className="absolute bottom-6 left-6 flex flex-col gap-2 font-mono text-[10px] text-emerald-400/80 pointer-events-none">
          <div className="flex gap-4">
            <span>RES: 1920x1080</span>
            <span>FPS: {camera.active ? '24.2' : '0.0'}</span>
            <span>BR: 4.8Mbps</span>
          </div>
          <div className="flex gap-4">
            <span>CODEC: H.264 High</span>
            <span>LATENCY: 42ms</span>
            <span>ENC: HARDWARE</span>
          </div>
        </div>

        {/* Center Risk Badge */}
        {camera.riskScore > 30 && (
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none">
            <div className={`flex flex-col items-center justify-center p-8 rounded-full border-4 ${
              camera.riskScore > 70 ? 'border-rose-500/50 bg-rose-500/10' : 'border-amber-500/50 bg-amber-500/10'
            } backdrop-blur-sm animate-pulse`}>
              <Activity className={`w-12 h-12 mb-2 ${camera.riskScore > 70 ? 'text-rose-500' : 'text-amber-500'}`} />
              <span className="text-white font-bold text-2xl">RISK: {camera.riskScore}%</span>
            </div>
          </div>
        )}
      </div>

      {/* Bottom Footer Overlay */}
      <div className="absolute bottom-0 left-0 right-0 z-20 p-6 bg-gradient-to-t from-black/80 to-transparent flex items-end justify-between pointer-events-none">
        <div className="flex gap-8">
           <div className="flex flex-col">
             <span className="text-xs text-slate-500 uppercase font-bold mb-1">Safety Index</span>
             <div className="h-1 w-32 bg-slate-800 rounded-full overflow-hidden">
               <div className="h-full bg-blue-500" style={{ width: `${100 - camera.riskScore}%` }}></div>
             </div>
           </div>
        </div>

        <div className="flex items-center gap-4 pointer-events-auto">
          <button className="flex items-center gap-2 px-4 py-2 bg-slate-900/80 border border-slate-700 text-slate-300 rounded-lg hover:bg-slate-800 transition-colors text-xs font-bold uppercase tracking-wider">
            <Maximize className="w-4 h-4" /> Full Screen
          </button>
        </div>
      </div>
    </div>
  );
};
